```class Solution {
    public int maxSubstrings(String word) {
        int count = 0;
        int maxCount = 0;
        char prev = word.charAt(0);
        int start = 0;
        for (int i = 1; i < word.length(); i++) {
            if (word.charAt(i) == prev) {
                start = i;
            } else {
                if (i - start >= 4) {
                    count++;
                }
                prev = word.charAt(i);
            }
        }
        if (word.length() - start >= 4) {
            count++;
        }
        return Math.max(count, maxCount);
    }
}```
